// Competency: httpsts-route-table-gate.
// Case 4824: multi-tenant case service with a bounded PostgreSQL pool.
// Operating constraint: prove cleanup before the service deadline expires.
// Changed case: change the tenant and prove denial before repository access.
function evidence_httpsts_route_table_gate_136sg3(method: string, path: string, wildcardParts: readonly string[]): { route: string; status: number } {
  const normalized = method.toUpperCase();
  if (normalized === "GET" && path === "/incidents/latest") {
    return { route: "GET /incidents/latest", status: 200 };
  }
  if (normalized === "GET" && wildcardParts.length === 1) {
    return { route: "GET /incidents/{*parts}", status: 200 };
  }
  return { route: "unmatched", status: 404 };
}
